describe("Temporal.PlainDateTime",()=>{describe("creation and parsing",()=>{it("can be created from an RFC 9557 string",()=>{let t=Temporal.PlainDateTime.from("2021-08-19T17:01:00");expect(t.toString()).toContain("2021-08-19T17:01:00")}),it("can be created from an own object",()=>{let t=Temporal.PlainDateTime.from("2021-08-19T17:01:00"),o=Temporal.PlainDateTime.from(t);expect(t).toEqual(o)}),it("can be created from an object containing properties",()=>{let t=Temporal.PlainDateTime.from({year:1995,month:12,day:7,hour:15});expect(t.toString()).toEqual("1995-12-07T15:00:00")})}),describe("arithmetic methods",()=>{let t=Temporal.PlainDateTime.from("2020-01-01T12:00:00"),o=Temporal.PlainDateTime.from("2020-01-02T12:00:00");it("add() advances the date/time",()=>{let e=t.add({days:1});expect(e.day).toBe(2)}),it("compare() method works for two PlainDateTime objects",()=>{expect(Temporal.PlainDateTime.compare(t,o)).toBe(-1),expect(Temporal.PlainDateTime.compare(o,t)).toBe(1),expect(Temporal.PlainDateTime.compare(t,t)).toBe(0)}),it("equals() verifies if two PlainDateTime are equal",()=>{let e=Temporal.PlainDateTime.from("2020-01-01T12:00:00");expect(t.equals(e)).toBe(!0)}),it("round() supports various forms, roundingMode, and roundingIncrement",()=>{let e=t.add({milliseconds:500}),c=e.round({smallestUnit:"second"});expect(c.second).toBe(1);let r=e.round({smallestUnit:"second",roundingMode:"trunc"});expect(r.second).toBe(0);let n=t.add({minutes:7,seconds:15}),a=n.round("minute");expect(a.minute).toBe(7),expect(a.second).toBe(0);let i=n.round({smallestUnit:"minute",roundingIncrement:15});expect(i.minute).toBe(0);let s=n.round({smallestUnit:"hour",roundingIncrement:2});expect(s.hour).toBe(12)}),it("since() returns correct duration",()=>{let e=o.since(t);expect(e.sign).toBe(1),expect(e.years).toBe(0),expect(e.months).toBe(0),expect(e.days).toBe(1),expect(e.hours).toBe(0),expect(e.minutes).toBe(0),expect(e.seconds).toBe(0),expect(e.milliseconds).toBe(0),expect(e.microseconds).toBe(0),expect(e.nanoseconds).toBe(0)}),it("subtract() decrements by a duration",()=>{let e=t.subtract({hours:1});expect(e.hour).toBeLessThan(t.hour)}),it("toPlainDate() returns a Temporal.PlainDate",()=>{let e=t.toPlainDate();expect(e).toBeInstanceOf(Temporal.PlainDate),expect(e.toString()).toBe("2020-01-01")}),it("toPlainTime() returns a Temporal.PlainTime",()=>{let e=t.toPlainTime();expect(e).toBeInstanceOf(Temporal.PlainTime),expect(e.toString()).toBe("12:00:00")}),it("toString() returns an ISO string representation",()=>{let e=t.toString();expect(typeof e).toBe("string"),expect(e).toBe("2020-01-01T12:00:00")}),it("until() returns correct duration",()=>{let e=t.until(o);expect(e.sign).toBe(1),expect(e.years).toBe(0),expect(e.months).toBe(0),expect(e.days).toBe(1),expect(e.hours).toBe(0),expect(e.minutes).toBe(0),expect(e.seconds).toBe(0),expect(e.milliseconds).toBe(0),expect(e.microseconds).toBe(0),expect(e.nanoseconds).toBe(0)}),it("valueOf() throws a TypeError",()=>{expect(()=>{+t}).toThrow()}),it("with() method returns a new PlainDateTime with updated fields",()=>{let e=t.with({day:15});expect(e.day).toBe(15),expect(e.month).toBe(t.month)})}),describe("properties",()=>{let t=Temporal.PlainDateTime.from("2020-01-01T12:00:00");it("should have correct date and time properties",()=>{expect(t.year).toBe(2020),expect(t.month).toBe(1),expect(t.day).toBe(1),expect(t.hour).toBe(12),expect(t.minute).toBe(0),expect(t.second).toBe(0),expect(t.millisecond).toBe(0),expect(t.microsecond).toBe(0),expect(t.nanosecond).toBe(0),expect(t.dayOfYear).toBe(1),expect(t.daysInMonth).toBe(31),expect(t.daysInYear).toBe(366),expect(t.inLeapYear).toBe(!0)}),it("has correct toStringTag",()=>{expect(Object.prototype.toString.call(t)).toBe("[object Temporal.PlainDateTime]")})})});
